import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const View = () => {
    const navigate = useNavigate();
    const [products, setProducts] = useState([]);
    const [searchWord, setSearchWord] = useState("");
   useEffect(() => {
        const customerId = localStorage.getItem("customerId");
        if (!customerId) {
            navigate("/customer/signin");
            return;
        }}, []);
    const fetchAllProducts = () => {
        axios.post("http://localhost:3001/allproducts")
            .then(response => {
                setProducts(response.data);
            })
            .catch(err => {
                console.error("Error fetching products:", err);
                alert("Could not fetch products.");
            });
    };

    useEffect(() => {
        fetchAllProducts();
    }, []);

    const handleSearchChange = (e) => {
        setSearchWord(e.target.value);
    };

    const handleSearch = () => {
        if (searchWord.trim() === "") {
            fetchAllProducts();
            return;
        }
        axios.post("http://localhost:3001/searchproducts", { name: searchWord })
            .then(response => {
                if (response.data.length > 0) {
                    setProducts(response.data);
                } else {
                    alert("No products found with that name.");
                    setProducts([]);
                }
            })
            .catch(err => {
                console.error("Error searching products:", err);
                alert("An error occurred during search.");
            });
    }
    const handleAddToCart = (productId) => {
        const customerId = sessionStorage.getItem("customerid");
        axios.post("http://localhost:3001/customer/addtocart", { customerId, productId })
            .then(response => {
                if (response.data.status === "success") {
                    alert("Product added to cart successfully.");
                } else {
                    alert("Failed to add product to cart.");
                }
            })
            .catch(err => {
                console.error("Error adding product to cart:", err);
                alert("An error occurred while adding product to cart.");
            });
    }

    return (
        <div className="container">
            <div className="row g-3 mt-3">
                <div className="col col-12 col-sm-12 col-md-12 col-lg-12 col-xl-12 col-xxl-12">
                    <input
                        type="search"
                        className="form-control"
                        name="search"
                        value={searchWord}
                        onChange={handleSearchChange}
                        placeholder="Enter product name to search"
                    />
                </div>
                <div className="col col-12 col-sm-12 col-md-12 col-lg-12 col-xl-12 col-xxl-12">
                    <button className="btn btn-primary w-100 mb-3" onClick={handleSearch}>Search</button>
                    <a href="/cart" className="btn btn-primary">View Cart</a>
                </div>
            </div>

            <div className="row g-3 mt-3">

                {products.length > 0 ? (
                    products.map((item, index) => (
                        <div key={index} className="col col-12 col-sm-12 col-md-12 col-lg-12 col-xl-12 col-xxl-12">
                            <div className="card h-100">
                                <div className="card-body">
                                    <h5 className="card-title">{item.name}</h5>
                                    <h6 className="card-subtitle mb-2 text-muted">${item.price}</h6>
                                    <p className="card-text">{item.description}</p>
                                    <p className="card-text"><small className="text-muted">Quantity: {item.quantity}</small></p>
                                    <p className="card-text"><small className="text-muted">Sold by: {item.sellerName}</small></p>
                                    <button className="btn btn-primary" onClick={() => handleAddToCart(item._id)}>Add to Cart</button>
                                </div>
                            </div>
                        </div>
                    ))
                ) : (
                    <div className="col col-12 col-sm-12 col-md-12 col-lg-12 col-xl-12 col-xxl-12">
                        <p>No products to display.</p>
                    </div>
                )}
            </div>
        </div>
    )
}

export default View
